<template>
  <section class="policies policies--dashboard">
    <div class="policies--dashboard__container">
      <div class="policies--dashboard__header">
        <SearchDashboard
          :model-value="settingsStore.policies.searchTerm"
          placeholder="Buscar Politicas..."
          class="policies--dashboard__search"
          @update:model-value="
            (value: string) => settingsStore.setSearchTerm(section, value)
          "
        />
        <FilterDefault
          :model-value="filters"
          :sort-options="sortOptions"
          class="policies--dashboard__filters"
          @update:model-value="handleFiltersChange"
        />
      </div>

      <p v-if="!isDraggable" class="policies--dashboard__drag-note">
        El arrastre para reordenar no esta disponible mientras se filtra.
      </p>

      <div class="policies--dashboard__table-wrapper">
        <div class="table table--default">
          <table class="table--default__table">
            <thead class="table--default__header">
              <tr class="table--default__row">
                <th class="table--default__head"></th>
                <th class="table--default__head">Orden</th>
                <th class="table--default__head">Título</th>
                <th class="table--default__head">Contenido</th>
                <th class="table--default__head">Fecha</th>
                <th class="table--default__head table--default__head--right">
                  Acciones
                </th>
              </tr>
            </thead>
            <draggable
              v-model="allPolicies"
              tag="tbody"
              item-key="id"
              handle=".policies--dashboard__drag"
              :disabled="!isDraggable"
              class="table--default__body"
              @end="handleReorder"
            >
              <template #item="{ element: policy }">
                <TableRow :key="policy.id">
                  <TableCell>
                    <button
                      class="policies--dashboard__drag"
                      :class="{
                        'policies--dashboard__drag--disabled': !isDraggable,
                      }"
                      :disabled="!isDraggable"
                      title="Arrastrar para reordenar"
                    >
                      <GripVertical class="policies--dashboard__drag__icon" />
                    </button>
                  </TableCell>
                  <TableCell>{{ policy.order ?? "-" }}</TableCell>
                  <TableCell>
                    <div
                      v-if="policy.title"
                      v-tooltip="
                        stripHtml(policy.title).length > 60
                          ? stripHtml(policy.title)
                          : ''
                      "
                      class="policies--dashboard__question"
                    >
                      {{ truncateText(policy.title, 60) }}
                    </div>
                    <div v-else class="policies--dashboard__question">-</div>
                  </TableCell>
                  <TableCell>
                    <div
                      v-if="policy.text"
                      v-tooltip="
                        stripHtml(policy.text).length > 80
                          ? stripHtml(policy.text)
                          : ''
                      "
                      class="policies--dashboard__answer"
                    >
                      {{ truncateText(policy.text, 80) }}
                    </div>
                    <div v-else class="policies--dashboard__answer">-</div>
                  </TableCell>
                  <TableCell>{{ formatDate(policy.updatedAt) }}</TableCell>
                  <TableCell align="right">
                    <div class="policies--dashboard__actions">
                      <button
                        class="policies--dashboard__action"
                        title="Ver Politica"
                        @click="handleViewPolicy(policy.documentId)"
                      >
                        <Eye class="policies--dashboard__action__icon" />
                      </button>
                      <button
                        class="policies--dashboard__action"
                        title="Editar Politica"
                        @click="handleEditPolicy(policy.documentId)"
                      >
                        <Pencil class="policies--dashboard__action__icon" />
                      </button>
                    </div>
                  </TableCell>
                </TableRow>
              </template>
            </draggable>
          </table>
        </div>

        <div
          v-if="allPolicies.length === 0 && !loading"
          class="policies--dashboard__empty"
        >
          <p>No se encontraron politicas</p>
        </div>

        <div v-if="loading" class="policies--dashboard__loading">
          <p>Cargando politicas...</p>
        </div>
      </div>

      <div class="policies--dashboard__footer">
        <p v-if="!loading" class="policies--dashboard__count">
          {{ allPolicies.length }} registro{{
            allPolicies.length !== 1 ? "s" : ""
          }}
        </p>
        <p v-if="saving" class="policies--dashboard__saving">
          Guardando orden...
        </p>
      </div>
    </div>
  </section>
</template>

<script setup lang="ts">
import { ref, computed, watch } from "vue";
import { useRouter } from "vue-router";
import { Eye, Pencil, GripVertical } from "lucide-vue-next";
import draggable from "vuedraggable";
import { useSettingsStore } from "@/stores/settings.store";
import { formatDate } from "@/utils/date";

interface Policy {
  id: number;
  documentId: string;
  title: string;
  text: string;
  order: number | null;
  updatedAt: string;
  createdAt: string;
}

const settingsStore = useSettingsStore();
const section = "policies" as const;

const filters = computed(() => settingsStore.getPoliciesFilters);

const handleFiltersChange = (newFilters: {
  sortBy: string;
  pageSize: number;
}) => {
  settingsStore.setFilters(section, newFilters);
};

const apiClient = useApiClient();
const allPolicies = ref<Policy[]>([]);
const loading = ref(false);
const saving = ref(false);

const isDraggable = computed(() => !settingsStore.policies.searchTerm);

const fetchPolicies = async () => {
  try {
    loading.value = true;

    const searchParams: Record<string, unknown> = {
      pagination: { pageSize: 200 },
      sort: settingsStore.policies.sortBy,
    };

    if (settingsStore.policies.searchTerm) {
      searchParams.filters = {
        $or: [
          { title: { $containsi: settingsStore.policies.searchTerm } },
          { text: { $containsi: settingsStore.policies.searchTerm } },
        ],
      };
    }

    const response = (await apiClient("policies", {
      method: "GET",
      params: searchParams as unknown as Record<string, unknown>,
    })) as {
      data: Policy[];
    };
    allPolicies.value = Array.isArray(response.data)
      ? (response.data as Policy[])
      : [];
  } catch (error) {
    console.error("Error fetching policies:", error);
    allPolicies.value = [];
  } finally {
    loading.value = false;
  }
};

const handleReorder = async () => {
  if (!isDraggable.value) return;
  saving.value = true;
  try {
    const updates = allPolicies.value.map((policy, index) => ({
      documentId: policy.documentId,
      order: index + 1,
    }));

    await apiClient("/policies/reorder", {
      method: "POST",
      body: { data: updates },
    });

    // Update local state to reflect new order values
    allPolicies.value = allPolicies.value.map((policy, index) => ({
      ...policy,
      order: index + 1,
    }));
  } catch (error) {
    console.error("Error saving policy order:", error);
    // Re-fetch to restore server state on failure
    await fetchPolicies();
  } finally {
    saving.value = false;
  }
};

const sortOptions = [
  { value: "order:asc", label: "Orden asc." },
  { value: "order:desc", label: "Orden desc." },
  { value: "createdAt:desc", label: "Más recientes" },
  { value: "createdAt:asc", label: "Más antiguos" },
  { value: "title:asc", label: "Título A-Z" },
  { value: "title:desc", label: "Título Z-A" },
];

const stripHtml = (html: string) => {
  if (!html) return "";
  // Remove HTML tags - safe for SSR
  if (typeof document === "undefined") {
    // Server-side: basic HTML tag removal
    return html.replace(/<[^>]*>/g, "").trim();
  }
  // Client-side: use DOM parser
  const tmp = document.createElement("DIV");
  tmp.innerHTML = html;
  return tmp.textContent || tmp.innerText || "";
};

const truncateText = (text: string, maxLength: number) => {
  if (!text) return "-";
  const cleanText = stripHtml(text);
  if (cleanText.length <= maxLength) return cleanText;
  return cleanText.slice(0, Math.max(0, maxLength)) + "...";
};

const router = useRouter();

const handleViewPolicy = (documentId: string) => {
  router.push(`/dashboard/maintenance/policies/${documentId}`);
};

const handleEditPolicy = (documentId: string) => {
  router.push(`/dashboard/maintenance/policies/${documentId}/edit`);
};

watch(
  [
    () => settingsStore.policies.searchTerm,
    () => settingsStore.policies.sortBy,
  ],
  () => {
    fetchPolicies();
  },
  { immediate: true },
);
</script>
